      <Route path="/admin" element={<h1>Admin Dashboard</h1>} />
      <Route path="/staff" element={<h1>Staff Dashboard</h1>} />
      <Route path="/gallery" element={<Gallery/>} />
    </Routes>
  );
}

export default App;
